import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { TASK_STATUSES, TASK_PRIORITIES } from '../../models/models';

@Component({
  selector: 'app-task-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './task-form.component.html',
  styleUrl: './tasks.css',
})
export class TaskFormComponent {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly statuses = TASK_STATUSES;
  readonly priorities = TASK_PRIORITIES;
  private pm = toSignal(this.route.paramMap, { initialValue: this.route.snapshot.paramMap });
  readonly editId = computed(() => this.pm().get('id'));
  readonly isEdit = computed(() => !!this.editId());

  form = this.fb.group({
    subject: ['', [Validators.required]],
    status: ['OPEN', [Validators.required]],
    priority: ['NORMAL', [Validators.required]],
    dueDate: ['', [Validators.required]],
    relatedTo: [''],
  });

  constructor() {
    if (this.isEdit()) {
      // Prefill with representative existing values for the mockup.
      this.form.patchValue({
        subject: 'Follow up on renewal quote',
        status: 'OPEN',
        priority: 'HIGH',
        dueDate: '2026-07-15',
        relatedTo: 'Acme Corporation',
      });
    }
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const target = this.isEdit() ? ['/tasks', this.editId()] : ['/tasks'];
    this.router.navigate(target);
  }

  cancel(): void {
    this.router.navigate(this.isEdit() ? ['/tasks', this.editId()] : ['/tasks']);
  }
}
